#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
vector<int> g[N];
int n,m,ans[N],f[N];
bool vis[N],flag;
void dfs(int u)
{
//	cout<<u<<endl;
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f[u]) continue;
//		cout<<v<<"  ";
		if(vis[v]&&(flag==0))
		{
//			cout<<"aaa\n";
			flag=1;
			int a=v,b=u;
			while(true)
			{
				int tmp=ans[a];
				ans[a]=b;
				b=a;
				a=tmp;
				if(tmp==0) break;
			}
		}
		else if(vis[v]==0)
		{
//			cout<<"bbb\n";
			ans[v]=f[v]=u;
			dfs(v);
		}
//		else cout<<"ccc\n";
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	for(int i=1;i<=n;i++)
	{
		if(!vis[i])
		{
			flag=0;
			dfs(i);
			if(flag==0)
			{
				cout<<"NIE";
				return 0;
			}
		}
	}
	cout<<"TAK\n";
	for(int i=1;i<=n;i++) cout<<ans[i]<<"\n";
	return 0;
}
